async function u(a){try{const t=await a.json();return t.detail?t.detail:null}catch(t){return console.warn("Failed to extract details: ",t),null}}function l(a){const t=new Date,c=new Date(a),e=Math.floor((t.getTime()-c.getTime())/1e3);if(e<5)return"just now";if(e<60)return`${e} seconds ago`;const n=Math.floor(e/60);if(n<60)return`${n} minute${n>1?"s":""} ago`;const r=Math.floor(n/60);if(r<24)return`${r} hour${r>1?"s":""} ago`;const o=Math.floor(r/24);if(o<30)return`${o} day${o>1?"s":""} ago`;const s=Math.floor(o/30);if(s<12)return`${s} month${s>1?"s":""} ago`;const i=Math.floor(o/365);return`${i} year${i>1?"s":""} ago`}export{u as e,l as t};
